const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

exports.serveCloudStorageFile = async (req, res) => {
  const { bucket, filePath } = req.query;

  // Validate required query parameters
  if (!bucket || !filePath) {
    res.status(400).send('Missing "bucket" or "filePath" query parameter.');
    return;
  }

  const file = storage.bucket(bucket).file(filePath);

  try {
    // Check if the file exists and retrieve its metadata
    // This allows setting the correct Content-Type and handles 404 explicitly
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send('File not found.');
      return;
    }

    const [metadata] = await file.getMetadata();

    // Set Content-Type header from file metadata, or default to octet-stream
    if (metadata && metadata.contentType) {
      res.set('Content-Type', metadata.contentType);
    } else {
      res.set('Content-Type', 'application/octet-stream');
    }

    // Set Content-Disposition for download, if desired
    // Example: res.set('Content-Disposition', `attachment; filename="${filePath.split('/').pop()}"`);

    // Create a readable stream from the Cloud Storage file
    const readStream = file.createReadStream();

    // Handle errors during streaming
    readStream.on('error', (err) => {
      console.error('Error streaming file from Cloud Storage:', err);
      if (err.code === 404) {
        // This case should ideally be caught by file.exists() above, but good for robustness
        res.status(404).send('File not found during stream.');
      } else {
        res.status(500).send('Error streaming file.');
      }
    });

    // Pipe the file stream directly to the HTTP response
    readStream.pipe(res);

    // The 'finish' event on the response indicates the stream has completed
    // No need to call res.end() explicitly as pipe handles it.
  } catch (error) {
    console.error('Error accessing Cloud Storage:', error);

    // Handle specific GCS errors
    if (error.code === 404) {
      res.status(404).send('Bucket or file not found.');
    } else if (error.code === 403) {
      res.status(403).send('Permission denied to access bucket or file.');
    } else {
      res.status(500).send('Internal server error.');
    }
  }
};